CREATE OR REPLACE FUNCTION fpa_fin_receipt_amount (as_vd_no char,ai_seqno integer) RETURNS bigint AS $body$
DECLARE

  ldc_item_amount bigint;
  ldc_int_amount bigint;

BEGIN
  select  item_amount into STRICT ldc_item_amount
  from    sc_fin_vourcher_detail
  where (seq_no = ai_seqno)
  and (vourcher_no = as_vd_no)
;
  select fpa_tel_receipt_lon_int(as_vd_no,ai_seqno) into STRICT ldc_int_amount;

  if ldc_item_amount = ldc_int_amount then
     ldc_item_amount := 0;
  end if;

  return coalesce(ldc_item_amount,0);

exception
when no_data_found then return 0;
when others then CALL spa_dberror('FPA_FIN_RECEIPT_AMOUNT');
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
